using System.Threading;
using System.Threading.Tasks;

/// <summary>
/// .NET 8 migration of the BackgroundProcessor.
///
/// KEY BREAKING CHANGES:
///
/// 1. Thread.Abort() throws PlatformNotSupportedException in .NET 6+.
///    It was removed because it corrupts app state — it can fire mid-lock,
///    mid-finally, or mid-write leaving objects half-mutated.
///
/// 2. Thread.ResetAbort() also throws PlatformNotSupportedException.
///
/// 3. ThreadAbortException is never raised by the .NET 8 runtime.
///    Catching it is dead code.
///
/// MIGRATION STRATEGY:
///   Replace Thread.Abort with cooperative cancellation via CancellationToken.
///   This is safer, testable, and works with async code.
/// </summary>
public class BackgroundProcessor : IDisposable
{
    private Thread? _workerThread;
    private readonly CancellationTokenSource _cts = new();

    public void Start()
    {
        _workerThread = new Thread(() => ProcessLoop(_cts.Token))
        {
            IsBackground = true
        };
        _workerThread.Start();
    }

    private void ProcessLoop(CancellationToken token)
    {
        while (!token.IsCancellationRequested)
        {
            try
            {
                // Pass the token so blocking calls can be interrupted immediately
                // instead of waiting for Thread.Abort that no longer exists.
                var item = GetNextItem(token);
                ProcessItem(item, token);
            }
            catch (OperationCanceledException) when (token.IsCancellationRequested)
            {
                // Graceful shutdown requested — roll back partial work
                RollbackCurrentTransaction();
                break; // exit the loop cleanly
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

    public void Stop()
    {
        _cts.Cancel(); // signal cancellation — non-blocking

        // Wait with a timeout instead of Thread.Sleep + Abort
        if (_workerThread is { IsAlive: true })
        {
            bool exited = _workerThread.Join(TimeSpan.FromSeconds(2));
            if (!exited)
            {
                // Log a warning — but do NOT call Thread.Abort().
                // If you reach here, fix GetNextItem/ProcessItem to
                // honor the CancellationToken properly.
                Console.Error.WriteLine(
                    "WARNING: Worker thread did not exit within timeout. " +
                    "Ensure all blocking calls accept CancellationToken.");
            }
        }
    }

    public void Dispose()
    {
        Stop();
        _cts.Dispose();
